function packBills(bills){const cap=257,base=32,lineH=7,maxLines=Math.max(1,Math.floor((cap-base)/lineH)),small=[],pages=[];bills.forEach(b=>{for(let i=0;i<b.lines.length;i+=maxLines){const part={...b,lines:b.lines.slice(i,i+maxLines)};part.h=base+part.lines.length*lineH;if(b.lines.length>maxLines)pages.push({items:[part],used:cap});else small.push(part)}});small.sort((a,b)=>b.h-a.h);small.forEach(b=>{let best=null,space=1e9;pages.forEach(p=>{let r=cap-p.used;if(b.h<=r&&r-b.h<space){best=p;space=r-b.h}});if(best){best.items.push(b);best.used+=b.h}else pages.push({items:[b],used:b.h})});return pages}
function preparePrint(){const pool=group(baseRows(),false),by={};Object.keys(send).forEach(k=>{const rec=k.split('|')[5],pk=k.split('|').slice(6).join('|'),qty=N(send[k]);if(!rec||qty<=0)return;const g=pool.find(x=>x.poolKey===pk);if(!g)return;(by[rec]??=[]).push({sku:g.code||'',name:g.sku,qty,unit:g.unit||0})});const bills=Object.entries(by).map(([store,lines])=>({store,ps:filters.ps||U(baseRows().map(r=>r.ps)).join(', '),date:dlabel(filters.end||filters.start),lines}));if(!bills.length){alert('ยังไม่ได้ใส่จำนวนส่งจริงให้ร้านใด');return}const data=JSON.stringify(packBills(bills));const w=window.open('','_blank');if(!w){alert('เบราว์เซอร์บล็อกหน้าปริ้น');return}w.document.write(`<!doctype html><html lang="th"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>เตรียมปริ้นบิล</title><style>@page{size:A4 portrait;margin:8mm}*{box-sizing:border-box}body{margin:0;background:#e5e7eb;font-family:system-ui,'Segoe UI',Tahoma,sans-serif;color:#111827}.bar{position:sticky;top:0;background:#0b6b31;color:#fff;padding:10px;display:flex;gap:8px;align-items:center;z-index:9}.bar button{border:0;border-radius:8px;padding:9px 14px;font-weight:900}.pages{padding:10px}.page{width:194mm;min-height:281mm;background:white;margin:0 auto 10px;padding:0;page-break-after:always;box-shadow:0 6px 20px #0002}.bill{padding:6mm 7mm;border-bottom:1px dashed #999;break-inside:avoid}.bill:last-child{border-bottom:0}.head{display:flex;justify-content:space-between;gap:8px;border-bottom:1px solid #111;padding-bottom:4px;margin-bottom:5px}.title{font-size:16px;font-weight:950}.meta{font-size:11px;line-height:1.4}.shop{font-size:15px;font-weight:950;margin:3px 0 5px}.tbl{width:100%;border-collapse:collapse;font-size:11px}.tbl th,.tbl td{border:1px solid #222;padding:3px 4px}.tbl th{background:#f3f4f6}.r{text-align:right}.c{text-align:center}.price{width:22mm;border:0;border-bottom:1px solid #111;text-align:right;font:inherit}.total{display:flex;justify-content:flex-end;gap:10mm;font-weight:950;margin-top:4px;font-size:12px}.sign{display:grid;grid-template-columns:1fr 1fr 1fr;gap:8mm;margin-top:8mm;font-size:11px;text-align:center}.sign div{border-top:1px solid #111;padding-top:2mm}@media print{body{background:white}.bar{display:none}.pages{padding:0}.page{box-shadow:none;margin:0;width:auto;min-height:auto}.bill{break-inside:avoid}}</style></head><body><div class="bar"><b>เตรียมปริ้นบิล A4 อัตโนมัติ</b><button onclick="window.print()">ปริ้น</button></div><div class="pages" id="pages"></div><script>const pages=${data};function money(n){return (Number(n)||0).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2})}function draw(){document.getElementById('pages').innerHTML=pages.map((p,pi)=>'<section class="page">'+p.items.map(b=>{let body=b.lines.map((l,i)=>'<tr><td class="c">'+(i+1)+'</td><td>'+l.sku+'</td><td>'+l.name+'</td><td class="r">'+l.qty+'</td><td class="r"><input class="price" data-q="'+l.qty+'" value="'+money(l.unit)+'"></td><td class="r amt">'+money(l.qty*l.unit)+'</td></tr>').join('');return '<div class="bill"><div class="head"><div><div class="title">ใบส่งสินค้า</div><div class="shop">'+b.store+'</div></div><div class="meta">วันที่: '+b.date+'<br>เซลล์: '+b.ps+'<br>หน้า: '+(pi+1)+'</div></div><table class="tbl"><thead><tr><th>#</th><th>รหัส</th><th>รายการสินค้า</th><th>จำนวน</th><th>ราคา/หน่วย</th><th>รวม</th></tr></thead><tbody>'+body+'</tbody></table><div class="total"><span>รวมชิ้น: <b class="qty"></b></span><span>รวมเงิน: <b class="sum"></b></span></div><div class="sign"><div>ผู้จัดของ</div><div>ผู้ส่ง</div><div>ผู้รับสินค้า</div></div></div>'}).join('')+'</section>').join('');calc()}function calc(){document.querySelectorAll('.bill').forEach(b=>{let q=0,s=0;b.querySelectorAll('.price').forEach(inp=>{let qty=Number(inp.dataset.q)||0,unit=Number(String(inp.value).replace(/,/g,''))||0,amt=qty*unit;q+=qty;s+=amt;inp.closest('tr').querySelector('.amt').textContent=money(amt)});b.querySelector('.qty').textContent=q.toLocaleString('th-TH');b.querySelector('.sum').textContent=money(s)})}document.addEventListener('input',e=>{if(e.target.className==='price')calc()});draw();<\/script></body></html>`);w.document.close()}
